def example_usage():
    kong = KongAdminAPI(admin_url="http://localhost:8001")
    
    try:
        status = kong.health_check()
        print(f"Kong Gateway Status: {status}")
    except Exception as e:
        print(f"Failed to connect to Kong Admin API: {e}")
        sys.exit(1)
    
    service_name = "example-api"
    service = kong.create_service(
        name=service_name,
        url="http://example.com",
        protocol="http",
        port=80,
        path="/api"
    )
    print(f"Service created: {service['id']}")
    
    route = kong.create_route(
        service_name_or_id=service_name,
        name="example-route",
        paths=["/example"],
        methods=["GET", "POST"],
        strip_path=True
    )
    print(f"Route created: {route['id']}")
    
    upstream_name = "example-upstream"
    upstream = kong.create_upstream(
        name=upstream_name,
        algorithm="round-robin",
        slots=1000,
        healthchecks={
            "active": {
                "healthy": {
                    "interval": 5,
                    "successes": 2
                },
                "unhealthy": {
                    "interval": 5,
                    "http_failures": 3,
                    "tcp_failures": 3,
                    "timeouts": 3
                }
            }
        }
    )
    print(f"Upstream created: {upstream['id']}")
    
    targets = [
        {"target": "backend1.example.com:8080", "weight": 100},
        {"target": "backend2.example.com:8080", "weight": 100},
        {"target": "backend3.example.com:8080", "weight": 50}
    ]
    
    for target_data in targets:
        target = kong.add_target(
            upstream_name_or_id=upstream_name,
            target=target_data["target"],
            weight=target_data["weight"]
        )
        print(f"Target added: {target_data['target']}")
    
    service_with_upstream = kong.create_service(
        name="load-balanced-api",
        host=upstream_name,
        protocol="http",
        path="/v1"
    )
    print(f"Load-balanced service created: {service_with_upstream['id']}")
    
    lb_route = kong.create_route(
        service_name_or_id=service_with_upstream['id'],
        name="lb-route",
        paths=["/lb-api"],
        methods=["GET", "POST", "PUT", "DELETE"]
    )
    print(f"Load-balanced route created: {lb_route['id']}")
    
    rate_limit_plugin = kong.add_plugin(
        plugin_name="rate-limiting",
        service_id=service['id'],
        config={
            "minute": 100,
            "hour": 1000,
            "policy": "local"
        }
    )
    print(f"Rate limiting plugin added: {rate_limit_plugin['id']}")
    
    cors_plugin = kong.add_plugin(
        plugin_name="cors",
        service_id=service_with_upstream['id'],
        config={
            "origins": ["*"],
            "methods": ["GET", "POST", "PUT", "DELETE"],
            "headers": ["Accept", "Content-Type", "Authorization"],
            "exposed_headers": ["X-Auth-Token"],
            "credentials": True,
            "max_age": 3600
        }
    )
    print(f"CORS plugin added: {cors_plugin['id']}")
    
    print("\n=== Configuration Summary ===")
    print(f"Services: {len(kong.list_services())}")
    print(f"Routes: {len(kong.list_routes())}")
    print(f"Upstreams: {len(kong.list_upstreams())}")
    print(f"Plugins: {len(kong.list_plugins())}")
    
    print("\n=== Targets in upstream ===")
    for target in kong.list_targets(upstream_name):
        print(f"  - {target['target']} (weight: {target['weight']})")


def configure_from_yaml(yaml_config: Dict):
    kong = KongAdminAPI(admin_url=yaml_config.get('kong_admin_url', 'http://localhost:8001'))
    
    for service_config in yaml_config.get('services', []):
        service = kong.create_service(**service_config)
        service_id = service['id']
        
        for route_config in service_config.get('routes', []):
            route_config['service_name_or_id'] = service_id
            kong.create_route(**route_config)
        
        for plugin_config in service_config.get('plugins', []):
            plugin_config['service_id'] = service_id
            kong.add_plugin(**plugin_config)
    
    for upstream_config in yaml_config.get('upstreams', []):
        targets = upstream_config.pop('targets', [])
        upstream = kong.create_upstream(**upstream_config)
        upstream_name = upstream['name']
        
        for target_config in targets:
            kong.add_target(upstream_name_or_id=upstream_name, **target_config)


if __name__ == "__main__":
    example_usage()